mapper.insert:
		/*
             SQL ID : OrgInfoDAO.insert
             설  명 : 기관 정보 등록
         */
		INSERT INTO TB_LMS_ORG (
			ORG_ID 
		  , ORGNM
		  , ORG_SYS_TYCD 
		  , DMNNM

		  , RPRS_TELNO

		  , ORG_NCNM

		  , RPRS_FAX

		  , ORG_REG_NO

		  , ORG_ZIP


		  , ORG_ADDR

		  , USEYN
		  , RGTR_ID
		  , FRST_INQ_DTTM
		) VALUES (
			#{orgId}
		  , #{orgNm}							    			
		  , 'UNI'
		  , #{domainNm}

		  , #{rprstPhoneNo}

		  , #{orgSnm}

		  , #{rprstFaxNo}

		  , #{orgBizNo}

		  , #{orgPost}


		  , #{orgAddr}

		  , #{dfltLangCd}
		  , 'Y'
		  , #{rgtrId}
		  , FN_DTTM()
		)

mapper.update:
		/*
             SQL ID : OrgInfoDAO.update
             설  명 : 기관 정보 수정
         */
		UPDATE TB_LMS_ORG
		SET
			  ORGNM			= #{orgNm}
			, DMNNM         = #{domainNm}

				, ORG_NCNM           = #{orgSnm}


				, ORG_ZIP          = #{orgPost}


				, ORG_ADDR          = #{orgAddr}


				, RPRS_TELNO    = #{rprstPhoneNo}


				, RPRS_FAX      = #{rprstFaxNo}


				, ORG_REG_NO        = #{orgBizNo}

			, MDFR_ID  			= #{mdfrId}
			, MOD_DTTM  		= FN_DTTM()
		WHERE ORG_ID = #{orgId}
